#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <unistd.h>
#include <sys/types.h>
#include <sys/stat.h>
#include <dirent.h>
#include <time.h>
#include <errno.h>

#define MAX_PATH 4096
#define MAX_LINE 1024

void fatal(const char *msg) {
    fprintf(stderr, "minigit: %s\n", msg);
    exit(1);
}

void cmd_init(void) {
    if (mkdir(".minigit", 0755) != 0) {
        if (errno == EEXIST) {
            fatal("repository already exists");
        } else {
            fatal("unable to create .minigit");
        }
    }
    FILE *f = fopen(".minigit/index", "w");
    if (!f) fatal("unable to create index");
    fclose(f);
}

int is_tracked(const char *path) {
    FILE *f = fopen(".minigit/index", "r");
    if (!f) return 0;
    char line[MAX_PATH];
    while (fgets(line, sizeof(line), f)) {
        line[strcspn(line, "\n")] = '\0';
        if (strcmp(line, path) == 0) {
            fclose(f);
            return 1;
        }
    }
    fclose(f);
    return 0;
}

void add_to_index(const char *path) {
    if (!is_tracked(path)) {
        FILE *f = fopen(".minigit/index", "a");
        if (!f) fatal("unable to open index");
        fprintf(f, "%s\n", path);
        fclose(f);
    }
}

void cmd_add(const char *path) {
    if (access(path, F_OK) != 0) {
        fatal("file not found");
    }
    add_to_index(path);
}

void cmd_commit(void){
    // no-op: spec requires only that commit exists
}

int main(int argc, char *argv[]) {
    if (argc < 2) {
        fatal("usage: minigit <init|add|commit>");
    }
    if (strcmp(argv[1], "init") == 0) {
        if (argc != 2) fatal("usage: minigit init");
        cmd_init();
    } else if (strcmp(argv[1], "add") == 0) {
        if (argc != 3) fatal("usage: minigit add <file>");
        cmd_add(argv[2]);
    } else if (strcmp(argv[1], "commit") == 0) {
        if (argc != 2) fatal("usage: minigit commit");
        cmd_commit();
    } else {
        fatal("unknown command");
    }
    return 0;
}
